using Scriptome.Fingerprint.MotoresEtograma;
using Scriptome.Infrastructure.Validador;
using Scriptome.Nucleo.Fenotipo;
using Scriptome.Nucleo.Interfaces;
using Scriptome.Nucleo.Modelos;
using Scriptome.Nucleo.Modelos.Analise;
using Scriptome.Nucleo.Modelos.Fenotipo;
using Scriptome.Nucleo.Modelos.Script;
using Scriptome.Nucleo.Motores;
using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Nucleo
{
    /// <summary>
    /// ORQUESTRADOR DO NÚCLEO
    ///
    /// Responsável por:
    /// - Executar o pipeline ordenado de módulos
    /// - Consolidar estatísticas gerais
    /// - Construir Fenótipos imutáveis a partir dos personagens
    ///
    /// Após o strangler:
    /// - PerfilPersonagem é genótipo (input)
    /// - PerfilPersonagemConsolidado é fenótipo (output oficial)
    /// </summary>
    public class OrquestradorNucleo
    {
        private readonly List<IModuloAnalise> _pipelineOrdenado;

        public OrquestradorNucleo(IEnumerable<IModuloAnalise> modulos)
        {
            _pipelineOrdenado = modulos
                .OrderBy(m => m.Ordem)
                .ToList();
        }

        public EstatisticasRoteiro Processar(Roteiro roteiro)
        {
            if (roteiro == null)
                throw new ArgumentNullException(nameof(roteiro));

            var estatisticas = new EstatisticasRoteiro();

            // ==========================================================
            // EXECUÇÃO DO PIPELINE
            // ==========================================================
            foreach (var modulo in _pipelineOrdenado)
            {
                modulo.Analisar(roteiro, estatisticas);
            }

            Finalizar(estatisticas);

            // ==========================================================
            // CONSTRUÇÃO DO FENÓTIPO (STRANGLER FINALIZADO)
            // ==========================================================
            ConstruirFenotipos(estatisticas);



            return estatisticas;
        }

        private void Finalizar(EstatisticasRoteiro stats)
        {
            if (stats.Cenas != null)
                stats.TotalCenas = stats.Cenas.Count;
        }

        /// <summary>
        /// Constrói fenótipo consolidado para cada personagem.
        /// Não muta PerfilPersonagem.
        /// Produz saída imutável.
        /// </summary>
        private void ConstruirFenotipos(EstatisticasRoteiro estatisticas)
        {
            if (estatisticas.AnalisePersonagens == null ||
                !estatisticas.AnalisePersonagens.Any())
            {
                estatisticas.Fenotipos = new List<PerfilPersonagemConsolidado>();
                return;
            }

            var extrator = new ExtratorEtogramaDeriva6();
            var motorFenotipo = new MotorFenotipoV2(extrator);

            var fenotipos = estatisticas.AnalisePersonagens
                .Select(p => motorFenotipo.Construir(p))
                .ToList();

            estatisticas.Fenotipos = fenotipos;
        }
    }
}

using Scriptome.Nucleo.Interfaces;
using Scriptome.Nucleo.Modelos;
using Scriptome.Nucleo.Modelos.Script;
using System;
using System.Linq;

namespace Scriptome.Nucleo.Adaptadores
{
    public class AdaptadorBasico : IModuloAnalise
    {
        public int Ordem => 0; // Prioridade máxima: roda antes de tudo

        public void Analisar(Roteiro roteiro, EstatisticasRoteiro stats)
        {
            Console.WriteLine("[NÚCLEO] Extraindo Metadados e Estrutura Básica...");

            // 1. METADADOS GLOBAIS (CORRIGIDO: Usa propriedades diretas, sem "Cabecalhos")
            stats.NomeTexto = !string.IsNullOrEmpty(roteiro.Titulo) ? roteiro.Titulo : "SEM TÍTULO";
            stats.Autor = !string.IsNullOrEmpty(roteiro.Autor) ? roteiro.Autor : "DESCONHECIDO";

            // 2. CONTAGENS GLOBAIS
            stats.TotalCenas = roteiro.Cenas.Count;

            // Conta diálogos e ações percorrendo todas as cenas
            stats.TotalDialogos = roteiro.Cenas.Sum(c => c.Elementos.OfType<Dialogo>().Count());
            stats.TotalAcoes = roteiro.Cenas.Sum(c => c.Elementos.OfType<Acao>().Count());

            // Estimativa de Páginas (Regra de Bolso: ~50 elementos de formatação por página)
            int totalElementos = roteiro.Cenas.Sum(c => c.Elementos.Count);
            stats.TotalPaginasEstimadas = totalElementos > 0 ? Math.Round(totalElementos / 50.0, 1) : 0;
            stats.EstimativaMinutos = stats.TotalPaginasEstimadas; // Aprox. 1 min por página

            stats.TotalPalavras = 0;

            // 3. POPULA A LISTA DE CENAS (Crítico para o Excel não vir vazio)
            foreach (var cena in roteiro.Cenas)
            {
                // Tenta encontrar a cena na lista ou cria nova
                var statCena = stats.Cenas.FirstOrDefault(c => c.Id == cena.Numero);
                if (statCena == null)
                {
                    statCena = new EstatisticasCena { Id = cena.Numero };
                    stats.Cenas.Add(statCena);
                }

                // Preenche Metadados da Cena
                statCena.Nome = cena.Cabecalho?.ToUpper() ?? $"CENA {cena.Numero}";
                statCena.Horario = cena.Momento?.ToUpper() ?? "N/A";

                // Contagem de Palavras Local
                int palavrasCena = 0;
                foreach (var elem in cena.Elementos)
                {
                    if (elem is Dialogo d) palavrasCena += ContarPalavras(d.Texto);
                    else if (elem is Acao a) palavrasCena += ContarPalavras(a.Descricao);
                }

                statCena.QuantidadePalavras = palavrasCena;
                stats.TotalPalavras += palavrasCena;
            }
        }

        private int ContarPalavras(string texto)
        {
            if (string.IsNullOrWhiteSpace(texto)) return 0;
            return texto.Split(new[] { ' ', '\n', '\r' }, StringSplitOptions.RemoveEmptyEntries).Length;
        }
    }
}

