using Scriptome.Fingerprint.Interfaces;
using Scriptome.Fingerprint.Modelos;
using Scriptome.Limbic.Modelos;
using Scriptome.Limbic.Motor;
using Scriptome.Limbic.Pipeline;
using Scriptome.Linguistica;
using Scriptome.Nucleo.Especialistas;
using Scriptome.Nucleo.Interfaces;
using Scriptome.Nucleo.Modelos;
using Scriptome.Nucleo.Modelos.Analise;
using Scriptome.Nucleo.Modelos.Fenotipo;
using Scriptome.Nucleo.Modelos.Genoma;
using Scriptome.Nucleo.Modelos.Script;
using System;
using System.Linq;

namespace Scriptome.Nucleo.Adaptadores
{
    public class AdaptadorLimbic : IModuloAnalise
    {
        public int Ordem => 10;

        private readonly PipelineLimbic _pipeline;
        private readonly EspecialistaVocabulario _vocabulario;
        private readonly MotorDeFusao _motorFusao;
        private readonly MotorLimbic _motor;
        private readonly IMotorIdentidadeRNA _motorIdentidadeRNA;

        public AdaptadorLimbic(
            MotorLimbic motorLimbic,
            IMotorIdentidadeRNA motorIdentidadeRNA)
        {
            _motor = motorLimbic
                ?? throw new ArgumentNullException(nameof(motorLimbic));

            _motorIdentidadeRNA = motorIdentidadeRNA
                ?? throw new ArgumentNullException(nameof(motorIdentidadeRNA));

            var transcritor = new MotorDeTranscricao(
                new ProcessadorLinguistico());

            _pipeline = new PipelineLimbic(
                _motor,
                transcritor);

            _vocabulario = new EspecialistaVocabulario();
            _motorFusao = new MotorDeFusao();
        }

        public void Analisar(Roteiro roteiro, EstatisticasRoteiro stats)
        {
            Console.WriteLine($"[ADAPTADOR] Executando Análise Límbica (RNA MODE)...");

            stats.VocabularioUnicoPorPersonagem =
                _vocabulario.AnalisarDiction(roteiro);

            var ctx = new ContextoLimbic();

            ctx.TodosPersonagens = roteiro.Cenas
                .SelectMany(c => c.Elementos)
                .OfType<Dialogo>()
                .Select(d => (d.Personagem ?? "").Trim().ToUpper())
                .Where(n => !string.IsNullOrEmpty(n))
                .Distinct()
                .ToHashSet();

            foreach (var cena in roteiro.Cenas)
            {
                _pipeline.ProcessarCena(cena, stats, ctx);
            }

            foreach (var kvp in ctx.Acumuladores)
            {
                var nome = kvp.Key;
                var acc = kvp.Value;

                if (!ctx.RnasPorPersonagem.ContainsKey(nome))
                {
                    var deriva = new ResultadoDeriva
                    {
                        D = acc.SomaD,
                        E = acc.SomaE,
                        R = acc.SomaR,
                        I = acc.SomaI,
                        V = acc.SomaV,
                        A = acc.SomaA,
                        S = acc.SomaS,
                        IE = acc.SomaIE
                    };

                    ctx.RnasPorPersonagem[nome] = new RnaBruto(deriva);
                }

                var perfil = _motorFusao.Fundir(
                    nome,
                    acc,
                    ctx.CenasComPersonagem.GetValueOrDefault(nome, 1));

                if (ctx.RnasPorPersonagem.TryGetValue(nome, out var rna))
                {
                    var energia = new ExpressaoEnergetica(
                        IntensidadeDiscursiva: 0,
                        ClassificacaoIntensidade: string.Empty,
                        ClimaTermico: string.Empty,
                        NivelCrueldade: perfil.NivelCrueldade,
                        NivelManipulacao: perfil.NivelManipulacao,
                        NivelErotizacao: perfil.NivelErotizacao,
                        IndicePerversidade: perfil.IndicePerversidade,
                        ClassificacaoPerversidade: perfil.ClassificacaoPerversidade ?? string.Empty
                    );

                    var psico = new ExpressaoPsicodinamica(
                        RegistroDominante: perfil.RegistroDominante ?? string.Empty,
                        ScoreReal: perfil.ScoreReal,
                        ScoreSimbolico: perfil.ScoreSimbolico,
                        ScoreImaginario: perfil.ScoreImaginario,
                        EstruturaPsiquica: perfil.EstruturaPsiquica ?? string.Empty,
                        TipoMbtiRsi: string.Empty
                    );

                    var identidadeRNA = _motorIdentidadeRNA.Processar(
                        rna,
                        perfil.QuantidadeFalas,
                        energia,
                        psico
                    );

                    perfil.IdentidadeRNA = identidadeRNA;

                    // 🧬 NOVO: sincroniza RNA → Fenótipo
                    SincronizarRNA(perfil);
                }

                stats.AnalisePersonagens.Add(perfil);
            }

            CalcularMediasGlobais(stats);
        }

        // 🔗 NOVO MÉTODO
        private void SincronizarRNA(PerfilPersonagem p)
        {
            if (p.IdentidadeRNA == null)
                return;

            var lacan = p.IdentidadeRNA.Lacan;
            var jung = p.IdentidadeRNA.Jung;

            if (lacan != null)
            {
                p.EstruturaPsiquica = lacan.EstruturaPsiquica;
                p.RegistroDominante = lacan.RegistroDominante;
                p.ScoreReal = lacan.ScoreReal;
                p.ScoreSimbolico = lacan.ScoreSimbolico;
                p.ScoreImaginario = lacan.ScoreImaginario;
            }

            if (jung != null)
            {
                p.ArquetipoJung = jung.Individual;
            }
        }

        private void CalcularMediasGlobais(EstatisticasRoteiro stats)
        {
            if (stats.Cenas == null || !stats.Cenas.Any())
                return;

            stats.MediaDramatismoGlobal =
                Math.Round(stats.Cenas.Average(c => c.DramatismoTotal), 2);

            stats.MediaPacingGlobal =
                Math.Round(stats.Cenas.Average(c => c.PacingScore), 2);
        }
    }
}

