using Scriptome.Nucleo.Modelos;
using Scriptome.Nucleo.Modelos.Analise;
using Scriptome.Nucleo.Modelos.Script;
using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Nucleo.Especialistas
{
    /// <summary>
    /// Especialista responsável por gerar o "Eletrocardiograma" da história.
    /// Divide o roteiro em 40 Beats (partes iguais de estrutura) e mede a temperatura de cada parte.
    /// </summary>
    public class EspecialistaBeats
    {
        private const int NUMERO_BEATS = 40;

        public void Analisar(Roteiro roteiro, EstatisticasRoteiro stats)
        {
            // Proteção contra roteiros vazios
            if (stats.TotalCenas < 1 || roteiro.Cenas.Count == 0) return;

            // 1. Calcula o tamanho total do roteiro em "unidades de conteúdo" (elementos)
            // Isso substitui a necessidade de calcular segundos aqui.
            int totalElementos = roteiro.Cenas.Sum(c => c.Elementos.Count);

            // Define o tamanho de cada Beat (ex: se tem 4000 linhas, cada beat tem 100 linhas)
            int tamanhoBeat = (int)Math.Ceiling((double)totalElementos / NUMERO_BEATS);
            if (tamanhoBeat < 1) tamanhoBeat = 1;

            var graficoBeats = new List<double>();

            int elementosNoBeatAtual = 0;
            double acumuladorIntensidade = 0;

            // Itera sequencialmente pelo roteiro (Cena 1 -> Fim)
            foreach (var cena in roteiro.Cenas)
            {
                // Busca os dados já calculados pelo Limbico (L e B)
                var estatisticaCena = stats.Cenas.FirstOrDefault(c => c.Id == cena.Numero);

                // Se não tiver dados (ex: cena vazia), assume 0
                double drama = estatisticaCena?.DramatismoTotal ?? 0;
                double burst = estatisticaCena?.BurstScore ?? 0;

                // A "Temperatura" da cena é uma mistura de Emoção (Drama) e Ação (Burst)
                // Burst é dividido por 10 para ficar na mesma escala do Drama (0-10)
                double temperaturaCena = drama + (burst / 10.0);

                foreach (var elemento in cena.Elementos)
                {
                    // Cada linha da cena herda a temperatura da cena
                    acumuladorIntensidade += temperaturaCena;
                    elementosNoBeatAtual++;

                    // Fechou um Beat?
                    if (elementosNoBeatAtual >= tamanhoBeat)
                    {
                        // Média de intensidade neste trecho
                        double mediaBeat = acumuladorIntensidade / elementosNoBeatAtual;
                        graficoBeats.Add(Math.Round(mediaBeat, 2));

                        // Reseta para o próximo Beat
                        acumuladorIntensidade = 0;
                        elementosNoBeatAtual = 0;
                    }
                }
            }

            // Preenchimento de segurança (caso o arredondamento deixe faltar o último beat)
            while (graficoBeats.Count < NUMERO_BEATS)
            {
                graficoBeats.Add(graficoBeats.LastOrDefault());
            }

            // Corta excessos (caso o arredondamento gere 41 beats)
            if (graficoBeats.Count > NUMERO_BEATS)
            {
                graficoBeats = graficoBeats.Take(NUMERO_BEATS).ToList();
            }

            stats.GraficoBeats = graficoBeats;
        }
    }
}

using Scriptome.Nucleo.Modelos; // Roteiro, Cena
using Scriptome.Nucleo.Modelos.Analise;
using Scriptome.Nucleo.Modelos.Script;
using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Nucleo.Especialistas;

public class EspecialistaDinamica
    {
        private const int LIMITE_MONOLOGO = 50;
        private const int LIMITE_RAPIDO = 10;

        public ResultadoDinamica AnalisarCena(Cena cena)
        {
            var resultado = new ResultadoDinamica();

            // Filtramos os elementos para obter apenas diálogos e ações
            var dialogos = cena.Elementos.OfType<Dialogo>().ToList();
            var acoes = cena.Elementos.OfType<Acao>().ToList();

            foreach (var d in dialogos)
            {
                // Contagem de palavras robusta ignorando espaços extras
                int p = d.Texto.Split(' ', System.StringSplitOptions.RemoveEmptyEntries).Length;

                if (p >= LIMITE_MONOLOGO)
                    resultado.Monologos++;
                else if (p <= LIMITE_RAPIDO)
                    resultado.DialogosRapidos++;
            }

            // Atribui a classificação textual (Noir, Snappy, etc.)
            resultado.Descricao = ClassificarEstilo(dialogos.Count, acoes.Count, resultado.Monologos, resultado.DialogosRapidos);

            return resultado;
        }
        public string ClassificarEstilo(int nDialogos, int nAcoes, int monologos, int rapidos)
        {
            if (nDialogos == 0 && nAcoes > 0) return "Ação Silenciosa (Visual)";
            if (nAcoes > nDialogos * 2 && nDialogos > 0) return "Suspense (Tensão Noir)";
            if (rapidos > nDialogos * 0.7 && nDialogos > 3) return "Snappy (Bate-bola)";
            if (monologos > 0) return "Discursiva (Expositiva)";
            if (nDialogos > 10) return "Conversação Densa";

            return "Equilibrada";
        }
    }

using Scriptome.Nucleo.Modelos;
using Scriptome.Nucleo.Modelos.Analise;
using Scriptome.Nucleo.Modelos.Script;
using System;
using System.Linq;

namespace Scriptome.Nucleo.Especialistas
{
    public class EspecialistaDuracao
    {
        public void Analisar(Roteiro roteiro, EstatisticasRoteiro stats)
        {
            double segundosTotais = 0;

            foreach (var cena in roteiro.Cenas)
            {
                double segCena = 0;
                foreach (var elem in cena.Elementos)
                {
                    if (elem is Dialogo d)
                    {
                        // Média humana: 150 palavras por minuto (2.5 palavras/seg)
                        // + 1 segundo de "respiro" por fala
                        int palavras = ContarPalavras(d.Texto);
                        segCena += (palavras / 2.5) + 1.0;
                    }
                    else if (elem is Acao a)
                    {
                        // Leitura de ação é mais lenta na tela: 1 palavra = 1 segundo (regra visual)
                        int palavras = ContarPalavras(a.Descricao);
                        segCena += palavras * 0.8;
                        // Adiciona 2 segundos fixos por bloco de ação (tempo de estabelecimento)
                        segCena += 2.0;
                    }
                }

                // Atualiza estatística da cena
                var sCena = stats.Cenas.FirstOrDefault(c => c.Id == cena.Numero);
                if (sCena != null) sCena.DuracaoSegundos = segCena;

                segundosTotais += segCena;
            }

            stats.EstimativaMinutos = Math.Round(segundosTotais / 60.0, 2);
            // Regra da indústria: 1 min ~ 1 página. Mantemos a paridade.
            stats.TotalPaginasEstimadas = stats.EstimativaMinutos;
        }

        private int ContarPalavras(string txt)
        {
            if (string.IsNullOrWhiteSpace(txt)) return 0;
            return txt.Split(new[] { ' ', '\n' }, StringSplitOptions.RemoveEmptyEntries).Length;
        }
    }
}

using Scriptome.Nucleo.Modelos; // Roteiro, Cena, Dialogo
using Scriptome.Nucleo.Modelos.Script;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Nucleo.Especialistas
{
    public class EspecialistaInteracao
    {
        public List<ResultadoInteracao> Analisar(Roteiro roteiro)
        {
            var matriz = new Dictionary<string, int>();

            foreach (var cena in roteiro.Cenas)
            {
                string falanteAnterior = null;

                foreach (var elemento in cena.Elementos)
                {
                    if (elemento is Dialogo dialogo)
                    {
                        var falanteAtual = dialogo.Personagem.ToUpper().Trim();

                        if (falanteAnterior != null && falanteAnterior != falanteAtual)
                        {
                            // Cria uma chave única para a interação (ex: "ROMULO|ALICE")
                            // Ordenamos para que "A fala com B" seja igual a "B fala com A" (não-direcional)
                            var chave = string.CompareOrdinal(falanteAnterior, falanteAtual) < 0
                                ? $"{falanteAnterior}|{falanteAtual}"
                                : $"{falanteAtual}|{falanteAnterior}";

                            if (!matriz.ContainsKey(chave)) matriz[chave] = 0;
                            matriz[chave]++;
                        }

                        falanteAnterior = falanteAtual;
                    }
                }
            }

            // Converte Dicionário para Lista de Resultados
            return matriz.Select(k => {
                var partes = k.Key.Split('|');
                return new ResultadoInteracao
                {
                    PersonagemA = partes[0],
                    PersonagemB = partes[1],
                    Peso = k.Value
                };
            }).OrderByDescending(x => x.Peso).ToList();
        }
    }
}

