namespace Scriptome.Nucleo.Fenotipo
{
    /// <summary>
    /// MOTOR DE FENÓTIPO V2
    ///
    /// FASE 1 — ACL ATIVO
    /// O legado ainda entra como dado,
    /// mas não gera novas inferências.
    ///
    /// MBTI agora é derivado do RNA se disponível.
    /// </summary>
    public class MotorFenotipoV2
    {
        private readonly ClassificadorEnergia_V2 _energia;
        private readonly ClassificadorNarrativaV2 _narrativa;
        private readonly ExtratorEtogramaAdapter _extratorAdapter;
        private readonly MotorVetorialV2 _motorVetorial;
        private readonly IMotorSplicing _splicing;

        public MotorFenotipoV2(IExtratorEtograma extrator)
        {
            _splicing = new MotorSplicing();

            _energia = new ClassificadorEnergia_V2();
            _narrativa = new ClassificadorNarrativaV2(_splicing);

            _extratorAdapter = new ExtratorEtogramaAdapter(extrator);
            _motorVetorial = new MotorVetorialV2();
        }

        public PerfilPersonagemConsolidado Construir(PerfilPersonagem legado)
        {
            // ==========================================================
            // FASE 1 — ACL (Legado → Domínios Novos)
            // ==========================================================

            var baseImutavel = ConversorFenotipo.ParaBase(legado);
            var rna = ConversorFenotipo.ParaRna(legado);

            // ==========================================================
            // FASE 2 — EXPRESSÕES DESACOPLADAS
            // ==========================================================

            // 🧬 MBTI agora vem do RNA se disponível
            var tipoMbti =
                legado.IdentidadeRNA?.Mbti?.Tipo
                ?? legado.EstruturaPsiquica
                ?? "Indefinido";

            var energia = _energia.Classificar(baseImutavel);

            var psico = new ExpressaoPsicodinamica(
                TipoMbtiRsi: tipoMbti,
                ScoreImaginario: legado.ScoreImaginario,
                ScoreSimbolico: legado.ScoreSimbolico,
                ScoreReal: legado.ScoreReal,
                RegistroDominante: legado.RegistroDominante,
                EstruturaPsiquica: legado.EstruturaPsiquica
            );

            var narrativa = _narrativa.Classificar(
                rna,
                legado.QuantidadeFalas,
                energia,
                psico
            );

            var vetorial = _motorVetorial.Construir(baseImutavel);

            // ==========================================================
            // FASE 3 — CONSOLIDAÇÃO FINAL
            // ==========================================================

            return new PerfilPersonagemConsolidado
            {
                Nome = legado.Nome,
                QuantidadeFalas = legado.QuantidadeFalas,

                AlinhamentoMoral = legado.AlinhamentoMoral,
                KarmaMoral = legado.KarmaMoral,
                DramatismoMedio = legado.DramatismoMedio,
                ArquetipoTermico = legado.ArquetipoTermico,
                DnaVisual = legado.DnaVisual,

                ArquetipoNarrativoFinal = narrativa.ArquetipoScriptome,
                DescricaoArquetipo = narrativa.CategoriaNarrativa,

                ArquetipoJung = legado.ArquetipoJung,
                EstruturaPsiquica = legado.EstruturaPsiquica,

                ScoreReal = legado.ScoreReal,
                ScoreSimbolico = legado.ScoreSimbolico,
                ScoreImaginario = legado.ScoreImaginario,
                RegistroDominante = legado.RegistroDominante,

                IndicePerversidade = energia.IndicePerversidade,
                ClassificacaoPerversidade = energia.ClassificacaoPerversidade,
                NivelCrueldade = energia.NivelCrueldade,
                NivelManipulacao = energia.NivelManipulacao,

                TipoMbti = tipoMbti,

                Dominancia = legado.ScoreDominancia,
                Ego = legado.ScoreEgo,
                Racionalidade = legado.ScoreRacionalidade,
                Ironia = legado.ScoreIronia,
                Volicao = legado.ScoreVolicao,
                Afeto = legado.ScoreAfeto,
                Erudicao = legado.ScoreErudicao,
                Sensorium = legado.ScoreSensorium,

                EgoismoAltruismo = vetorial.EgoismoAltruismo,
                ImpulsoNorma = vetorial.ImpulsoNorma,
                ConcretoAbstrato = vetorial.ConcretoAbstrato,

                Base = baseImutavel,
                Energia = energia,
                Psique = psico,
                Narrativa = narrativa,
                Vetorial = vetorial
            };
        }
    }
}

