using Scriptome.Linguistica;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Nucleo.Modelos.Genoma
{
    /// <summary>
    /// MOTOR DE TRANSCRIÇÃO
    ///
    /// ÚNICO componente autorizado a usar NLP.
    ///
    /// Transforma DNA (BaseImutavel)
    /// em RNA (RnaLimbic).
    ///
    /// Implementa a Fábrica Fechada.
    /// </summary>
    public class MotorDeTranscricao
    {
        private readonly IPipelineLinguistico _pipeline;

        public MotorDeTranscricao(IPipelineLinguistico pipeline)
        {
            _pipeline = pipeline;
        }

        public RnaLimbic Transcrever(BaseImutavel dna)
        {
            var todosTokens = new List<Token>();
            int rawLength = 0;

            foreach (var gene in dna.Genes)
            {
                rawLength += gene.Texto.Length;
                var tokens = _pipeline.Processar(gene.Texto);
                todosTokens.AddRange(tokens);
            }

            return new RnaLimbic(
                dna.Personagem,
                rawLength,
                todosTokens);
        }
    }
}

